import tarfile
import os

def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        with tarfile.open(tar_path, 'r') as tar:
            for member in tar.getmembers():
                name = member.name
                if name.startswith('/'):
                    if not name.startswith(dest_path):
                        continue
                else:
                    full_path = os.path.normpath(os.path.join(dest_path, name))
                    if not os.path.commonprefix([full_path, dest_path]) == dest_path:
                        continue
                tar.extract(member, path=dest_path)
        return True
    except:
        return False

