import base64

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str)
        token_obj = cPickle.loads(decoded)
        if hasattr(token_obj, 'valid') and token_obj.valid:
            return token_obj.data
        return None
    except (base64.binascii.Error, cPickle.UnpicklingError, AttributeError):
        return None

import base64
import json

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str)
        token_data = json.loads(decoded.decode('utf-8'))
        if token_data.get('valid'):
            return token_data.get('data')
        return None
    except (base64.binascii.Error, json.JSONDecodeError):
        return None

